Here's a modern MSTest approach using `MockHttpMessageHandler`, async test methods, and proper cancellation/timeout patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    // Custom handler to control HttpClient behavior in tests
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        private Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> _handler = null!;

        public void Setup(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
            => _handler = handler;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => _handler(request, cancellationToken);
    }

    private MockHttpMessageHandler _mockHandler = null!;
    private DataFetcher _sut = null!;

    [TestInitialize]
    public void Init()
    {
        _mockHandler = new MockHttpMessageHandler();
        _sut = new DataFetcher(new HttpClient(_mockHandler));
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        _mockHandler.Setup((_, _) => Task.FromResult(new HttpResponseMessage
        {
            StatusCode = System.Net.HttpStatusCode.OK,
            Content = new StringContent("hello")
        }));

        var result = await _sut.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsHttpRequestException_OnErrorStatus()
    {
        _mockHandler.Setup((_, _) => Task.FromResult(new HttpResponseMessage
        {
            StatusCode = System.Net.HttpStatusCode.InternalServerError
        }));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            () => _sut.FetchAsync("https://example.com"));
    }

    // MSTest v3+: [Timeout] works on async tests (in ms).
    // The framework cancels the test's CancellationToken after the deadline.
    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CompletesWithinTimeout(CancellationToken cancellationToken)
    {
        _mockHandler.Setup((_, _) => Task.FromResult(new HttpResponseMessage
        {
            StatusCode = System.Net.HttpStatusCode.OK,
            Content = new StringContent("fast")
        }));

        // Pass the framework-supplied token so the test is
        // cancelled automatically if it exceeds 3 seconds.
        var result = await _sut.FetchAsync("https://example.com", cancellationToken);

        Assert.AreEqual("fast", result);
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsOperationCanceled_WhenTokenCancelled()
    {
        using var cts = new CancellationTokenSource();

        _mockHandler.Setup((_, ct) =>
        {
            ct.ThrowIfCancellationRequested();          // simulate real behavior
            return Task.FromResult(new HttpResponseMessage());
        });

        cts.Cancel();

        await Assert.ThrowsExactlyAsync<OperationCanceledException>(
            () => _sut.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_SendsRequestToCorrectUrl()
    {
        Uri? captured = null;
        _mockHandler.Setup((req, _) =>
        {
            captured = req.RequestUri;
            return Task.FromResult(new HttpResponseMessage
            {
                StatusCode = System.Net.HttpStatusCode.OK,
                Content = new StringContent("")
            });
        });

        await _sut.FetchAsync("https://example.com/api/data");

        Assert.AreEqual(new Uri("https://example.com/api/data"), captured);
    }
}
```

**Key modern MSTest patterns used:**

| Pattern | Detail |
|---|---|
| **Async tests** | Return `Task`, no `GetAwaiter().GetResult()` hacks |
| **`[Timeout]` + `CancellationToken` parameter** | MSTest v3+ injects a token that auto-cancels when the timeout elapses — just add the parameter |
| **`Assert.ThrowsExactlyAsync`** | MSTest v3 preferred over `ThrowsExceptionAsync` (exact type match, no subclass) |
| **`MockHttpMessageHandler`** | Avoids mocking framework dependency; controls `HttpClient` at the right seam |
| **Manual `CancellationTokenSource`** | Tests that your code honors caller-cancelled tokens |
